def solve():
    import sys
    input = sys.stdin.readline

    N, M, H, K = map(int, input().split())
    S = input().strip()
    items = set()
    for _ in range(M):
        x, y = map(int, input().split())
        items.add((x, y))

    x, y = 0, 0
    health = H

    for move in S:
        if move == 'R':
            x += 1
        elif move == 'L':
            x -= 1
        elif move == 'U':
            y += 1
        elif move == 'D':
            y -= 1

        health -= 1
        if health < 0:
            print("No")
            return

        if (x, y) in items and health < K:
            health = K
